SELECT COUNT(*) 
FROM association_rules
WHERE support > 0.05 AND confidence > 0.1;

SELECT item_id 
FROM item_support 
WHERE support_value = (SELECT MAX(support_value) FROM item_support);

SELECT ROUND(AVG(c.loyalty_points), 2) AS average_loyalty_points
FROM customers c
JOIN customer_segments cs ON c.customer_id = cs.customer_id;

SELECT SUM(budget) 
FROM campaigns
WHERE campaign_id IN (SELECT campaign_id FROM rule_usage);
